1	const PROCESSING_FEE = 5;
2	const INITIAL_ASSESSMENT_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	};
10	type QuoteResult = { premium: number };
11	type ScenarioResult = { results: QuoteResult[] };
12	
13	const BASE_PREMIUM: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	  rune: 25,
19	  moonstone: 25,
20	};
21	
22	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
23	const BLOCK_SIZE = 3;
24	const BLOCK_OF_THREE_PREMIUM = 60;
25	
26	const priceSameTypeGroup = (type: string, count: number): number =>
27	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
28	    ? BLOCK_OF_THREE_PREMIUM
29	    : count * BASE_PREMIUM[type];
30	
31	const countByType = (items: Item[]): Map<string, number> => {
32	  const counts = new Map<string, number>();
33	  for (const item of items) {
34	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
35	  }
36	  return counts;
37	};
38	
39	const sumBasePremiums = (items: Item[]): number =>
40	  Array.from(countByType(items)).reduce(
41	    (total, [type, count]) => total + priceSameTypeGroup(type, count),
42	    0,
43	  );
44	
45	const quotePremium = (items: Item[]): number => {
46	  const base = sumBasePremiums(items);
47	  const surcharge = base * INITIAL_ASSESSMENT_SURCHARGE_RATE;
48	  return Math.ceil(base + surcharge) + PROCESSING_FEE;
49	};
50	
51	export const runScenario = (input: Scenario): ScenarioResult => {
52	  const results = input.steps.map((step) => ({ premium: quotePremium(step.items) }));
53	  return { results };
54	};
